94	void choose_wall_rows() {
95	    double best_score = -1;
96	    int best_top = 8, best_bot = 23;
97	
98	    // Try all pairs of wall rows with enough separation
99	    for (int tr = 3; tr <= 15; tr++) {
100	        for (int br = tr + 4; br <= 28; br++) {
101	            int pets_above = 0, pets_between = 0, pets_below = 0;
102	            for (auto& p : pets) {
103	                if (p.r < tr) pets_above++;
104	                else if (p.r > br) pets_below++;
105	                else pets_between++; // includes pets ON the wall rows
106	            }
107	
108	            int area_above = (tr - 1) * GRID_SIZE;
109	            int area_below = (GRID_SIZE - br) * GRID_SIZE;
110	
111	            // Humans in each zone: roughly M/2 each
112	            int humans_top = M / 2;
113	            int humans_bot = M - humans_top;
114	
115	            double score_above = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
116	            double score_below = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
117	
118	            // Average satisfaction
119	            double avg_score = (score_above * humans_top + score_below * humans_bot) / M;
120	
121	            // Penalize if walls are far from humans
122	            double avg_dist_top = 0, avg_dist_bot = 0;
123	            for (int i = 0; i < M; i++) {
124	                avg_dist_top += std::abs(humans[i].r - tr);
125	                avg_dist_bot += std::abs(humans[i].r - br);
126	            }
127	            avg_dist_top /= M;
128	            avg_dist_bot /= M;
129	            double avg_dist = (avg_dist_top + avg_dist_bot) / 2.0;
130	
131	            // Penalize: building two walls of 30 each takes ~60/M turns + travel
132	            double time_penalty = 1.0 / (1.0 + avg_dist * 0.03);
133	
134	            double score = avg_score * time_penalty;
135	
136	            if (score > best_score) {
137	                best_score = score;
138	                best_top = tr;
139	                best_bot = br;
140	            }
141	        }
142	    }
143	
144	    // Also consider single wall (compare scores)
145	    double best_single = -1;
146	    int best_single_row = 15;
147	    bool best_single_top = true;
148	    for (int r = 3; r <= 28; r++) {
149	        int pets_above = 0, pets_below = 0;
150	        for (auto& p : pets) {
151	            if (p.r < r) pets_above++;
152	            else if (p.r > r) pets_below++;
153	            else { pets_above++; pets_below++; }
154	        }
155	        int area_above = (r - 1) * GRID_SIZE;
156	        int area_below = (GRID_SIZE - r) * GRID_SIZE;
157	        double sa = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
158	        double sb = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
159	        bool top = sa >= sb;
160	        double sc = top ? sa : sb;
161	        double avg_d = 0;
162	        for (int i = 0; i < M; i++) avg_d += std::abs(humans[i].r - r);
163	        avg_d /= M;
164	        sc *= 1.0 / (1.0 + avg_d * 0.03);
165	        if (sc > best_single) {
166	            best_single = sc;
167	            best_single_row = r;
168	            best_single_top = top;
169	        }
170	    }
171	
172	    if (best_single > best_score * 1.1) {
173	        // Single wall is significantly better, use it
174	        if (best_single_top) {
175	            top_wall_row = best_single_row;
176	            bot_wall_row = 0; // sentinel: no bottom wall
177	        } else {
178	            top_wall_row = 0;
179	            bot_wall_row = best_single_row;
180	        }
181	    } else {
182	        top_wall_row = best_top;
183	        bot_wall_row = best_bot;
184	    }
185	}
