# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

// Strategy: Build two horizontal wall lines to create a "pet cage" in between.
// The safe zones are above the top wall and below the bottom wall.
// Split humans: half build top wall, half build bottom wall.
// Each human then moves to their respective safe zone.

int top_wall_row, bot_wall_row;

void choose_wall_rows() {
    double best_score = -1;
    int best_top = 8, best_bot = 23;

    // Try all pairs of wall rows with enough separation
    for (int tr = 3; tr <= 15; tr++) {
        for (int br = tr + 4; br <= 28; br++) {
            int pets_above = 0, pets_between = 0, pets_below = 0;
            for (auto& p : pets) {
                if (p.r < tr) pets_above++;
                else if (p.r > br) pets_below++;
                else pets_between++; // includes pets ON the wall rows
            }

            int area_above = (tr - 1) * GRID_SIZE;
            int area_below = (GRID_SIZE - br) * GRID_SIZE;

            // Humans in each zone: roughly M/2 each
            int humans_top = M / 2;
            int humans_bot = M - humans_top;

            double score_above = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
            double score_below = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);

            // Average satisfaction
            double avg_score = (score_above * humans_top + score_below * humans_bot) / M;

            // Penalize if walls are far from humans
            double avg_dist_top = 0, avg_dist_bot = 0;
            for (int i = 0; i < M; i++) {
                avg_dist_top += std::abs(humans[i].r - tr);
                avg_dist_bot += std::abs(humans[i].r - br);
            }
            avg_dist_top /= M;
            avg_dist_bot /= M;
            double avg_dist = (avg_dist_top + avg_dist_bot) / 2.0;

            // Penalize: building two walls of 30 each takes ~60/M turns + travel
            double time_penalty = 1.0 / (1.0 + avg_dist * 0.03);

            double score = avg_score * time_penalty;

            if (score > best_score) {
                best_score = score;
                best_top = tr;
                best_bot = br;
            }
        }
    }

    // Also consider single wall (compare scores)
    double best_single = -1;
    int best_single_row = 15;
    bool best_single_top = true;
    for (int r = 3; r <= 28; r++) {
        int pets_above = 0, pets_below = 0;
        for (auto& p : pets) {
            if (p.r < r) pets_above++;
            else if (p.r > r) pets_below++;
            else { pets_above++; pets_below++; }
        }
        int area_above = (r - 1) * GRID_SIZE;
        int area_below = (GRID_SIZE - r) * GRID_SIZE;
        double sa = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
        double sb = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
        bool top = sa >= sb;
        double sc = top ? sa : sb;
        double avg_d = 0;
        for (int i = 0; i < M; i++) avg_d += std::abs(humans[i].r - r);
        avg_d /= M;
        sc *= 1.0 / (1.0 + avg_d * 0.03);
        if (sc > best_single) {
            best_single = sc;
            best_single_row = r;
            best_single_top = top;
        }
    }

    if (best_single > best_score * 1.1) {
        // Single wall is significantly better, use it
        if (best_single_top) {
            top_wall_row = best_single_row;
            bot_wall_row = 0; // sentinel: no bottom wall
        } else {
            top_wall_row = 0;
            bot_wall_row = best_single_row;
        }
    } else {
        top_wall_row = best_top;
        bot_wall_row = best_bot;
    }
}

enum Phase { PHASE_BUILD, PHASE_MOVE_SAFE };
