    if (top_wall_row > 0 && bot_wall_row > 0) {
        // Two walls: assign humans greedily
        std::vector<std::pair<int,int>> dist_to_top(M), dist_to_bot(M);
        for (int i = 0; i < M; i++) {
            dist_to_top[i] = {std::abs(humans[i].r - top_wall_row), i};
            dist_to_bot[i] = {std::abs(humans[i].r - bot_wall_row), i};
        }

        // Assign half to top, half to bottom based on proximity
        int top_count = M / 2;
        int bot_count = M - top_count;

        // Greedy: sort by (dist_to_top - dist_to_bot), assign those preferring top first
        std::vector<std::pair<int,int>> preference(M);
        for (int i = 0; i < M; i++) {
            preference[i] = {std::abs(humans[i].r - top_wall_row) - std::abs(humans[i].r - bot_wall_row), i};
        }
        std::sort(preference.begin(), preference.end());

        int assigned_top = 0;
        int assigned_bot = 0;
        for (auto& [pref, idx] : preference) {
            if (assigned_top < top_count) {
                human_wall_assignment[idx] = 0;
                assigned_top++;
            } else {
                human_wall_assignment[idx] = 1;
                assigned_bot++;
            }
        }
    } else if (top_wall_row > 0) {
        for (int i = 0; i < M; i++) human_wall_assignment[i] = 0;
    } else {
        for (int i = 0; i < M; i++) human_wall_assignment[i] = 1;
    }

    for (int i = 0; i < M; i++) human_phase[i] = PHASE_BUILD;

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;
        bool col_claimed_top[GRID_SIZE + 2], col_claimed_bot[GRID_SIZE + 2];
        memset(col_claimed_top, false, sizeof(col_claimed_top));
        memset(col_claimed_bot, false, sizeof(col_claimed_bot));

        // Process humans
        for (int i = 0; i < M; i++) {
            int my_wall_row = (human_wall_assignment[i] == 0) ? top_wall_row : bot_wall_row;
            bool* my_claimed = (human_wall_assignment[i] == 0) ? col_claimed_top : col_claimed_bot;

            if (my_wall_row <= 0) {
                human_phase[i] = PHASE_MOVE_SAFE;
            }

            if (human_phase[i] == PHASE_BUILD) {
                // Find nearest unbuilt, unclaimed column
                int target_col = -1;
                int min_dist = INF;

                for (int c = 1; c <= GRID_SIZE; c++) {
                    if (grid[my_wall_row][c] || my_claimed[c]) continue;
                    int dist = std::abs(humans[i].r - my_wall_row) + std::abs(humans[i].c - c);
                    if (dist < min_dist) {
