                                    walls_being_built.push_back({my_wall_row, target_col});
                                    break;
                                }
                            }
                        } else {
                            // Pet blocking, try adjacent column
                            my_claimed[target_col] = false;
                            int alt_col = -1;
                            for (int c = 1; c <= GRID_SIZE; c++) {
                                if (c == target_col) continue;
                                if (grid[my_wall_row][c] || my_claimed[c]) continue;
                                if (!can_build_wall(my_wall_row, c)) continue;
                                bool adjacent = false;
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == my_wall_row &&
                                        humans[i].c + DC[d] == c) {
                                        adjacent = true;
                                        break;
                                    }
                                }
                                if (adjacent) { alt_col = c; break; }
                            }
                            if (alt_col != -1) {
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == my_wall_row &&
                                        humans[i].c + DC[d] == alt_col) {
                                        actions[i] = BUILD_CH[d];
                                        walls_being_built.push_back({my_wall_row, alt_col});
                                        my_claimed[alt_col] = true;
                                        break;
                                    }
                                }
                            } else {
                                actions[i] = '.';
                            }
                        }
                    } else {
                        actions[i] = move_toward(humans[i], stand_pos);
                    }
                }
            }

            if (human_phase[i] == PHASE_MOVE_SAFE) {
                int safe_r;
                if (human_wall_assignment[i] == 0) {
                    // Safe zone is above top_wall_row
                    int wr = (top_wall_row > 0) ? top_wall_row : bot_wall_row;
                    safe_r = std::max(1, wr / 2);
                } else {
                    // Safe zone is below bot_wall_row
                    int wr = (bot_wall_row > 0) ? bot_wall_row : top_wall_row;
                    safe_r = std::min(GRID_SIZE, wr + (GRID_SIZE - wr) / 2);
                }
                int safe_c = GRID_SIZE / 2;
                Point target = {safe_r, safe_c};

                if (!passable(target.r, target.c)) {
                    int search_start, search_end;
                    if (human_wall_assignment[i] == 0) {
                        search_start = 1;
                        search_end = (top_wall_row > 0) ? top_wall_row - 1 : GRID_SIZE;
                    } else {
                        search_start = (bot_wall_row > 0) ? bot_wall_row + 1 : 1;
                        search_end = GRID_SIZE;
                    }
                    bool found = false;
                    for (int r = search_start; r <= search_end && !found; r++) {
                        for (int c = 1; c <= GRID_SIZE && !found; c++) {
                            if (passable(r, c)) {
                                target = {r, c};
                                found = true;
                            }
                        }
                    }
                }

                if (humans[i] == target) {
                    actions[i] = '.';
                } else {
                    actions[i] = move_toward(humans[i], target);
                }
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
