    switch (target_quadrant) {
        case 0: stand_row_offset = -1; stand_col_offset = -1; break; // TL: above, left
        case 1: stand_row_offset = -1; stand_col_offset = 1; break;  // TR: above, right
        case 2: stand_row_offset = 1; stand_col_offset = -1; break;  // BL: below, left
        case 3: stand_row_offset = 1; stand_col_offset = 1; break;   // BR: below, right
