constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

// Cross wall strategy: one horizontal + one vertical wall creating 4 quadrants
// All humans concentrate in the quadrant with fewest initial pets

int wall_row, wall_col;
int target_quadrant; // 0=TL, 1=TR, 2=BL, 3=BR

struct QuadrantInfo {
    int pets;
    int area;
    double score;
};

void choose_cross_walls() {
    double best_score = -1;
    int best_row = 15, best_col = 15, best_quad = 0;

    for (int wr = 4; wr <= 27; wr++) {
        for (int wc = 4; wc <= 27; wc++) {
            int pets_tl = 0, pets_tr = 0, pets_bl = 0, pets_br = 0;
            for (auto& p : pets) {
                if (p.r < wr && p.c < wc) pets_tl++;
                else if (p.r < wr && p.c > wc) pets_tr++;
                else if (p.r > wr && p.c < wc) pets_bl++;
                else if (p.r > wr && p.c > wc) pets_br++;
                // Pets ON wall row/col are trapped by the wall itself
            }

            int area_tl = (wr - 1) * (wc - 1);
            int area_tr = (wr - 1) * (GRID_SIZE - wc);
            int area_bl = (GRID_SIZE - wr) * (wc - 1);
            int area_br = (GRID_SIZE - wr) * (GRID_SIZE - wc);

            QuadrantInfo quads[4] = {
                {pets_tl, area_tl, 0},
                {pets_tr, area_tr, 0},
                {pets_bl, area_bl, 0},
                {pets_br, area_br, 0}
            };

            for (int q = 0; q < 4; q++) {
                quads[q].score = (double)quads[q].area / 900.0 * std::pow(2.0, -(double)quads[q].pets);
            }

            // Find best quadrant
            int best_q = 0;
            for (int q = 1; q < 4; q++) {
                if (quads[q].score > quads[best_q].score) best_q = q;
            }

            // Penalize by human travel distance to target quadrant center
            int target_r, target_c;
            switch (best_q) {
                case 0: target_r = wr / 2; target_c = wc / 2; break;
                case 1: target_r = wr / 2; target_c = wc + (GRID_SIZE - wc) / 2; break;
                case 2: target_r = wr + (GRID_SIZE - wr) / 2; target_c = wc / 2; break;
                case 3: target_r = wr + (GRID_SIZE - wr) / 2; target_c = wc + (GRID_SIZE - wc) / 2; break;
            }

            double avg_dist = 0;
            for (int i = 0; i < M; i++) {
                avg_dist += std::abs(humans[i].r - target_r) + std::abs(humans[i].c - target_c);
