                                            break;
                                        }
                                    }
                                    if (adjacent) { alt_row = r; break; }
                                }
                                if (alt_row != -1) {
                                    for (int d = 0; d < 4; d++) {
                                        if (humans[i].r + DR[d] == alt_row &&
                                            humans[i].c + DC[d] == wall_col) {
                                            actions[i] = BUILD_CH[d];
                                            walls_being_built.push_back({alt_row, wall_col});
                                            v_claimed[alt_row] = true;
                                            break;
                                        }
                                    }
                                } else {
                                    actions[i] = '.';
                                }
                            }
                        } else {
                            actions[i] = move_toward(humans[i], stand_pos);
                        }
                    }
                }
            }

            if (human_phase[i] == PHASE_MOVE_SAFE) {
                // Move to center of target quadrant
                int target_r, target_c;
                switch (target_quadrant) {
                    case 0: target_r = wall_row / 2; target_c = wall_col / 2; break;
                    case 1: target_r = wall_row / 2; target_c = wall_col + (GRID_SIZE - wall_col) / 2; break;
                    case 2: target_r = wall_row + (GRID_SIZE - wall_row) / 2; target_c = wall_col / 2; break;
                    case 3: target_r = wall_row + (GRID_SIZE - wall_row) / 2; target_c = wall_col + (GRID_SIZE - wall_col) / 2; break;
                }
                target_r = std::max(1, std::min(GRID_SIZE, target_r));
                target_c = std::max(1, std::min(GRID_SIZE, target_c));

                Point target = {target_r, target_c};
                if (!passable(target.r, target.c)) {
                    // Find nearest passable cell in target quadrant
                    int r_start, r_end, c_start, c_end;
                    switch (target_quadrant) {
                        case 0: r_start=1; r_end=wall_row-1; c_start=1; c_end=wall_col-1; break;
                        case 1: r_start=1; r_end=wall_row-1; c_start=wall_col+1; c_end=GRID_SIZE; break;
