# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

// Strategy: Find a narrow band (2-5 rows) with 0 initial pets.
// Build walls on both sides of this band. All humans enter the band.
// Score = band_area/900 * 2^0 = band_area/900 (guaranteed no pets if sealed fast enough).
// Fallback: if no 0-pet band exists, choose band with fewest pets.

int top_wall_row, bot_wall_row; // walls at these rows; safe band is between them (exclusive)

void choose_band() {
    double best_score = -1;
    int best_top = -1, best_bot = -1;

    // Try all pairs: top_wall at row t, bot_wall at row b
    // Safe band = rows t+1 to b-1
    // We want: 0 or minimal pets in rows t+1..b-1
    // Band width = b - t - 1

    for (int t = 1; t <= 28; t++) {
        for (int b = t + 2; b <= 30; b++) { // at least 1 row between walls
            int band_width = b - t - 1;
            int band_area = band_width * GRID_SIZE;

            // Count pets in the band (rows t+1 to b-1)
            int pets_in_band = 0;
            for (auto& p : pets) {
                if (p.r > t && p.r < b) pets_in_band++;
            }

            double raw_score = (double)band_area / 900.0 * std::pow(2.0, -(double)pets_in_band);

            // Penalty for walls needed (both walls combined = 60 cells if both are full rows)
            // If t==1 or b==30, we use the boundary (no wall needed on that side)
            int walls_needed = 0;
            if (t >= 1 && t <= 30) walls_needed += GRID_SIZE; // top wall at row t
            if (b >= 1 && b <= 30) walls_needed += GRID_SIZE; // bot wall at row b
            // Boundary optimization: row 0 and row 31 are boundaries
            // If t == 0, the top is the boundary (no wall needed)
            // But t must be >= 1 for a valid wall row
            // If t == 1 and the safe band starts at row 2... we still need wall at row 1
            // Actually, grid boundary: outside rows 1-30 is impassable
            // So rows 1-30 are the grid. A wall at row 1 = row 1 is impassable.
            // Safe band above row 1 doesn't exist.
            // If band is rows 1..X, the top is bounded by the boundary (no wall needed at top)
            // We just need bot wall at row X+1
            bool need_top_wall = (t >= 2); // if t=1, top of band IS the boundary
            bool need_bot_wall = (b <= 29); // if b=30, bottom of band IS the boundary

            // Redefine: safe band includes boundary
            // Let's reconsider: band = rows from r_start to r_end
            // Top is bounded if r_start == 1 (grid boundary above)
            // Bottom is bounded if r_end == 30 (grid boundary below)
            // Wall needed on top if r_start > 1: wall at row r_start - 1
            // Wall needed on bot if r_end < 30: wall at row r_end + 1
            // But wait, the wall itself blocks passage. The wall at row t means row t is impassable.
            // Safe band rows: t+1 to b-1.
            // If t == 0: band starts at row 1, bounded by grid top. But t=0 is not a valid grid row.
            // So if we want the band to START at row 1: we don't need a top wall (grid boundary handles it).
            //   In this case, top_wall_row = 0 (sentinel: no top wall)
            //   Band = rows 1 to b-1, bot_wall = b
            // If we want band to END at row 30: we don't need bot wall.
            //   top_wall = t, band = rows t+1 to 30, bot_wall = 31 (sentinel)

            walls_needed = 0;
            int actual_band_start, actual_band_end;

            if (t == 0) {
                actual_band_start = 1;
                walls_needed += 0; // top bounded by grid
            } else {
                actual_band_start = t + 1;
                walls_needed += GRID_SIZE;
            }
            if (b == 31) {
                actual_band_end = 30;
                walls_needed += 0;
            } else {
                actual_band_end = b - 1;
                walls_needed += GRID_SIZE;
            }

            // Recalculate for this iteration where t is in [1..28], b in [t+2..30]
            // So t >= 1, b <= 30. Always need both walls.
            walls_needed = 2 * GRID_SIZE; // 60 cells

            // Avg distance of humans to the band center
            double band_center = (t + 1 + b - 1) / 2.0;
            double avg_dist = 0;
            for (int i = 0; i < M; i++) {
                avg_dist += std::abs(humans[i].r - band_center);
            }
            avg_dist /= M;

            // Time to build: walls_needed/M + avg_dist
            double build_time = (double)walls_needed / M + avg_dist;

            // Penalize configurations that take too long (pets might wander in)
            // Narrower bands are less likely to have pets wander in during construction
            double time_factor = 1.0 / (1.0 + build_time * 0.01);

            double score = raw_score * time_factor;

            if (score > best_score) {
                best_score = score;
                best_top = t;
                best_bot = b;
            }
        }
    }

    // Also try bands touching boundaries (only 1 wall needed)
    // Band at top: rows 1 to X, only need wall at row X+1
    for (int b = 3; b <= 29; b++) {
        int band_width = b - 1; // rows 1 to b-1
        int band_area = band_width * GRID_SIZE;
        int pets_in_band = 0;
        for (auto& p : pets) {
