        }
        avg_dist /= M;
        double build_time = (double)walls_needed / M + avg_dist;
        double time_factor = 1.0 / (1.0 + build_time * 0.01);
        double score = raw_score * time_factor;

        if (score > best_score) {
            best_score = score;
            best_top = 0; // no top wall (boundary)
            best_bot = b;
        }
    }

    // Band at bottom: rows X+1 to 30, only need wall at row X
    for (int t = 2; t <= 28; t++) {
        int band_width = GRID_SIZE - t; // rows t+1 to 30
        int band_area = band_width * GRID_SIZE;
        int pets_in_band = 0;
        for (auto& p : pets) {
            if (p.r > t) pets_in_band++;
        }
        double raw_score = (double)band_area / 900.0 * std::pow(2.0, -(double)pets_in_band);
        int walls_needed = GRID_SIZE;

        double band_center = (t + 1 + GRID_SIZE) / 2.0;
        double avg_dist = 0;
        for (int i = 0; i < M; i++) {
