        }
        avg_dist /= M;
        double build_time = (double)walls_needed / M + avg_dist;
        double time_factor = 1.0 / (1.0 + build_time * 0.01);
        double score = raw_score * time_factor;

        if (score > best_score) {
            best_score = score;
            best_top = t;
            best_bot = 31; // no bot wall (boundary)
        }
    }

    top_wall_row = best_top;
    bot_wall_row = best_bot;
}

enum Phase { PHASE_BUILD_TOP, PHASE_BUILD_BOT, PHASE_ENTER_BAND, PHASE_DONE };
Phase human_phase[10];

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_band();

    // Determine safe band boundaries
    int band_start = (top_wall_row == 0) ? 1 : top_wall_row + 1;
    int band_end = (bot_wall_row == 31) ? 30 : bot_wall_row - 1;

    // Assign humans: split between top wall and bot wall builders
    // If only one wall needed, all humans build that wall
    bool need_top = (top_wall_row > 0 && top_wall_row <= 30);
    bool need_bot = (bot_wall_row > 0 && bot_wall_row <= 30);

    if (need_top && need_bot) {
        // Split humans: those closer to top build top, rest build bot
        std::vector<std::pair<int,int>> preference(M);
        for (int i = 0; i < M; i++) {
            int dt = std::abs(humans[i].r - top_wall_row);
            int db = std::abs(humans[i].r - bot_wall_row);
            preference[i] = {dt - db, i};
        }
        std::sort(preference.begin(), preference.end());

        int top_count = M / 2;
        int assigned = 0;
        for (auto& [pref, idx] : preference) {
            if (assigned < top_count) {
                human_phase[idx] = PHASE_BUILD_TOP;
            } else {
                human_phase[idx] = PHASE_BUILD_BOT;
            }
            assigned++;
        }
    } else if (need_top) {
        for (int i = 0; i < M; i++) human_phase[i] = PHASE_BUILD_TOP;
    } else if (need_bot) {
        for (int i = 0; i < M; i++) human_phase[i] = PHASE_BUILD_BOT;
    } else {
        for (int i = 0; i < M; i++) human_phase[i] = PHASE_ENTER_BAND;
    }

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        bool top_claimed[GRID_SIZE + 2], bot_claimed[GRID_SIZE + 2];
        memset(top_claimed, false, sizeof(top_claimed));
        memset(bot_claimed, false, sizeof(bot_claimed));

        for (int i = 0; i < M; i++) {
            if (human_phase[i] == PHASE_BUILD_TOP || human_phase[i] == PHASE_BUILD_BOT) {
                int my_wall_row = (human_phase[i] == PHASE_BUILD_TOP) ? top_wall_row : bot_wall_row;
                bool* my_claimed = (human_phase[i] == PHASE_BUILD_TOP) ? top_claimed : bot_claimed;

                if (my_wall_row <= 0 || my_wall_row > 30) {
                    human_phase[i] = PHASE_ENTER_BAND;
                    // fall through to ENTER_BAND below
                } else {
                    // Check if wall is complete
                    bool wall_complete = true;
                    for (int c = 1; c <= GRID_SIZE; c++) {
                        if (!grid[my_wall_row][c]) { wall_complete = false; break; }
                    }

                    if (wall_complete) {
                        human_phase[i] = PHASE_ENTER_BAND;
                    } else {
                        // Build from edges toward center for faster sealing
                        int target_col = -1;
                        int min_dist = INF;

                        for (int c = 1; c <= GRID_SIZE; c++) {
                            if (grid[my_wall_row][c] || my_claimed[c]) continue;
                            // Prefer edge columns (distance from nearest edge)
                            int edge_priority = std::min(c - 1, GRID_SIZE - c);
                            int dist = std::abs(humans[i].c - c) + std::abs(humans[i].r - my_wall_row) * 2 + edge_priority;
                            if (dist < min_dist) {
                                min_dist = dist;
                                target_col = c;
                            }
                        }

                        if (target_col == -1) {
                            human_phase[i] = PHASE_ENTER_BAND;
                        } else {
                            my_claimed[target_col] = true;

                            // Stand on the band side of the wall to build
                            int stand_r;
                            if (human_phase[i] == PHASE_BUILD_TOP) {
                                stand_r = my_wall_row + 1; // below top wall = inside band
                            } else {
                                stand_r = my_wall_row - 1; // above bot wall = inside band
                            }

                            // But if we're NOT in the band yet, stand on whichever side we're on
                            if (humans[i].r < my_wall_row) {
                                stand_r = my_wall_row - 1;
                            } else if (humans[i].r > my_wall_row) {
                                stand_r = my_wall_row + 1;
                            }
                            // If ON the wall row, try band side
                            if (humans[i].r == my_wall_row) {
                                if (human_phase[i] == PHASE_BUILD_TOP) {
                                    stand_r = my_wall_row + 1;
                                } else {
                                    stand_r = my_wall_row - 1;
                                }
                            }

                            Point stand_pos = {stand_r, target_col};

                            if (!valid(stand_r, target_col) || !passable(stand_r, target_col)) {
                                // Try other side
                                int alt_r = (stand_r == my_wall_row - 1) ? my_wall_row + 1 : my_wall_row - 1;
                                if (valid(alt_r, target_col) && passable(alt_r, target_col)) {
                                    stand_pos = {alt_r, target_col};
                                } else {
                                    actions[i] = '.';
                                    continue;
                                }
                            }

                            if (humans[i] == stand_pos) {
                                if (can_build_wall(my_wall_row, target_col)) {
                                    for (int d = 0; d < 4; d++) {
                                        if (humans[i].r + DR[d] == my_wall_row &&
                                            humans[i].c + DC[d] == target_col) {
                                            actions[i] = BUILD_CH[d];
                                            walls_being_built.push_back({my_wall_row, target_col});
                                            break;
                                        }
                                    }
                                } else {
                                    // Try adjacent buildable column
                                    my_claimed[target_col] = false;
                                    int alt_col = -1;
                                    for (int c = 1; c <= GRID_SIZE; c++) {
                                        if (c == target_col) continue;
                                        if (grid[my_wall_row][c] || my_claimed[c]) continue;
                                        if (!can_build_wall(my_wall_row, c)) continue;
                                        bool adjacent = false;
                                        for (int d = 0; d < 4; d++) {
                                            if (humans[i].r + DR[d] == my_wall_row &&
                                                humans[i].c + DC[d] == c) {
                                                adjacent = true;
                                                break;
                                            }
                                        }
                                        if (adjacent) { alt_col = c; break; }
                                    }
