        double time_factor = 1.0 / (1.0 + build_time * 0.01);
        double score = raw_score * time_factor;

        if (score > best_score) {
            best_score = score;
            best_top = 0; // no top wall (boundary)
            best_bot = b;
        }
    }

    // Band at bottom: rows X+1 to 30, only need wall at row X
    for (int t = 2; t <= 28; t++) {
        int band_width = GRID_SIZE - t; // rows t+1 to 30
        int band_area = band_width * GRID_SIZE;
        int pets_in_band = 0;
