        double time_factor = 1.0 / (1.0 + build_time * 0.01);
        double score = raw_score * time_factor;

        if (score > best_score) {
            best_score = score;
            best_top = t;
            best_bot = 31; // no bot wall (boundary)
        }
    }

    top_wall_row = best_top;
    bot_wall_row = best_bot;
}

enum Phase { PHASE_BUILD_TOP, PHASE_BUILD_BOT, PHASE_ENTER_BAND, PHASE_DONE };
