// This allows ALL humans to cooperate on both walls and stay in the same zone.

int top_wall_row, bot_wall_row; // walls at these rows
// Safe band = rows top_wall_row+1 to bot_wall_row-1

// Also compare against boundary variants:
// - Top boundary: safe = rows 1..X, wall at X+1 (built from inside at row X doing 'd')
// - Bot boundary: safe = rows X..30, wall at X-1 (built from inside at row X doing 'u')
// But boundary variants still need humans inside to build the wall.

int band_start, band_end; // actual safe band rows

void choose_band() {
    double best_score = -1;

    // Two walls (middle band): top_wall at T, bot_wall at B
    // Band = rows T+1 to B-1. Humans build from inside.
    for (int t = 2; t <= 27; t++) {
        for (int b = t + 3; b <= 29; b++) { // at least 2 rows between walls
            int band_width = b - t - 1;
            int band_area = band_width * GRID_SIZE;

            int pets_in_band = 0;
            for (auto& p : pets) {
                if (p.r > t && p.r < b) pets_in_band++;
            }

            double raw_score = (double)band_area / 900.0 * std::pow(2.0, -(double)pets_in_band);

            // Cost: 60 cells total wall, all M humans cooperate
            // Avg distance of humans to band center
            double band_center = (t + 1 + b - 1) / 2.0;
            double avg_dist = 0;
            for (int i = 0; i < M; i++) {
                avg_dist += std::abs(humans[i].r - band_center) + std::min(std::abs(humans[i].c - GRID_SIZE/2), 5);
            }
            avg_dist /= M;

            double build_time = 60.0 / M + avg_dist;
            double time_factor = 1.0 / (1.0 + build_time * 0.02);

            double score = raw_score * time_factor;

            if (score > best_score) {
                best_score = score;
                top_wall_row = t;
                bot_wall_row = b;
            }
        }
    }

    // Also try boundary variants (only 1 wall needed)
    // Top boundary: safe = rows 1 to B-1, wall at B (built from inside at row B-1 doing 'd')
    for (int b = 3; b <= 15; b++) {
        int band_width = b - 1;
        int band_area = band_width * GRID_SIZE;
        int pets_in_band = 0;
        for (auto& p : pets) {
            if (p.r < b) pets_in_band++;
        }
        double raw_score = (double)band_area / 900.0 * std::pow(2.0, -(double)pets_in_band);
        double band_center = b / 2.0;
        double avg_dist = 0;
        for (int i = 0; i < M; i++) {
            avg_dist += std::abs(humans[i].r - band_center);
        }
        avg_dist /= M;
        double build_time = 30.0 / M + avg_dist;
        double time_factor = 1.0 / (1.0 + build_time * 0.02);
        double score = raw_score * time_factor;

        if (score > best_score) {
            best_score = score;
            top_wall_row = 0; // sentinel: top boundary
            bot_wall_row = b;
        }
    }

    // Bot boundary: safe = rows T+1 to 30, wall at T (built from inside at row T+1 doing 'u')
    for (int t = 16; t <= 28; t++) {
        int band_width = GRID_SIZE - t;
        int band_area = band_width * GRID_SIZE;
        int pets_in_band = 0;
        for (auto& p : pets) {
            if (p.r > t) pets_in_band++;
        }
        double raw_score = (double)band_area / 900.0 * std::pow(2.0, -(double)pets_in_band);
        double band_center = (t + 1 + GRID_SIZE) / 2.0;
        double avg_dist = 0;
        for (int i = 0; i < M; i++) {
            avg_dist += std::abs(humans[i].r - band_center);
        }
        avg_dist /= M;
        double build_time = 30.0 / M + avg_dist;
        double time_factor = 1.0 / (1.0 + build_time * 0.02);
        double score = raw_score * time_factor;

        if (score > best_score) {
            best_score = score;
            top_wall_row = t;
            bot_wall_row = 31; // sentinel: bot boundary
        }
    }

    // Set actual band
    band_start = (top_wall_row == 0) ? 1 : top_wall_row + 1;
    band_end = (bot_wall_row == 31) ? 30 : bot_wall_row - 1;
}

enum Phase { PHASE_ENTER, PHASE_BUILD, PHASE_DONE };
Phase human_phase[10];

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_band();

    for (int i = 0; i < M; i++) {
        // If already in the band, go straight to building
        if (humans[i].r >= band_start && humans[i].r <= band_end) {
            human_phase[i] = PHASE_BUILD;
        } else {
            human_phase[i] = PHASE_ENTER;
        }
    }

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        bool top_claimed[GRID_SIZE + 2], bot_claimed[GRID_SIZE + 2];
        memset(top_claimed, false, sizeof(top_claimed));
        memset(bot_claimed, false, sizeof(bot_claimed));

        // Check if walls are complete
        bool top_complete = true, bot_complete = true;
        if (top_wall_row >= 1 && top_wall_row <= 30) {
            for (int c = 1; c <= GRID_SIZE; c++) {
                if (!grid[top_wall_row][c]) { top_complete = false; break; }
            }
        }
        if (bot_wall_row >= 1 && bot_wall_row <= 30) {
            for (int c = 1; c <= GRID_SIZE; c++) {
                if (!grid[bot_wall_row][c]) { bot_complete = false; break; }
            }
        }

        for (int i = 0; i < M; i++) {
            if (human_phase[i] == PHASE_ENTER) {
                // Move into the band
                int target_r = (band_start + band_end) / 2;
                int target_c = humans[i].c; // keep same column for efficiency

                // Clamp to band
                target_r = std::max(band_start, std::min(band_end, target_r));
                target_c = std::max(1, std::min(GRID_SIZE, target_c));

                Point target = {target_r, target_c};
                if (!passable(target.r, target.c)) {
                    for (int c = 1; c <= GRID_SIZE; c++) {
                        if (passable(target_r, c)) {
                            target = {target_r, c};
                            break;
                        }
                    }
                }

                if (humans[i].r >= band_start && humans[i].r <= band_end) {
                    human_phase[i] = PHASE_BUILD;
                    // Fall through to build phase
                } else {
                    actions[i] = move_toward(humans[i], target);
                    continue;
                }
            }

            if (human_phase[i] == PHASE_BUILD) {
                if (top_complete && bot_complete) {
                    human_phase[i] = PHASE_DONE;
                    actions[i] = '.';
                    continue;
                }

                // Find best wall cell to build
                // Priority: whichever wall has more remaining cells, build nearest
                int best_target_r = -1, best_target_c = -1;
                int min_travel = INF;

                // Try top wall
                if (!top_complete && top_wall_row >= 1 && top_wall_row <= 30) {
                    for (int c = 1; c <= GRID_SIZE; c++) {
                        if (grid[top_wall_row][c] || top_claimed[c]) continue;
                        // To build at (top_wall_row, c), human must be at (top_wall_row+1, c)
                        // which is band_start if top_wall_row+1 == band_start
                        int stand_r = top_wall_row + 1;
                        if (stand_r < band_start || stand_r > band_end) continue; // can't stand there
                        int dist = std::abs(humans[i].r - stand_r) + std::abs(humans[i].c - c);
                        if (dist < min_travel) {
                            min_travel = dist;
                            best_target_r = top_wall_row;
                            best_target_c = c;
                        }
                    }
                }

                // Try bot wall
                if (!bot_complete && bot_wall_row >= 1 && bot_wall_row <= 30) {
                    for (int c = 1; c <= GRID_SIZE; c++) {
                        if (grid[bot_wall_row][c] || bot_claimed[c]) continue;
                        int stand_r = bot_wall_row - 1;
                        if (stand_r < band_start || stand_r > band_end) continue;
                        int dist = std::abs(humans[i].r - stand_r) + std::abs(humans[i].c - c);
                        if (dist < min_travel) {
                            min_travel = dist;
                            best_target_r = bot_wall_row;
                            best_target_c = c;
                        }
                    }
                }

                if (best_target_r == -1) {
                    human_phase[i] = PHASE_DONE;
                    actions[i] = '.';
                    continue;
                }

                // Claim this cell
                if (best_target_r == top_wall_row) {
                    top_claimed[best_target_c] = true;
                } else {
                    bot_claimed[best_target_c] = true;
                }

                // Stand position: adjacent to wall, inside band
                int stand_r = (best_target_r == top_wall_row) ? top_wall_row + 1 : bot_wall_row - 1;
                Point stand_pos = {stand_r, best_target_c};

                if (humans[i] == stand_pos) {
                    if (can_build_wall(best_target_r, best_target_c)) {
                        // Find build direction
                        for (int d = 0; d < 4; d++) {
                            if (humans[i].r + DR[d] == best_target_r &&
                                humans[i].c + DC[d] == best_target_c) {
                                actions[i] = BUILD_CH[d];
                                walls_being_built.push_back({best_target_r, best_target_c});
                                break;
                            }
                        }
                    } else {
                        // Pet blocking - try another cell on same wall
                        if (best_target_r == top_wall_row) top_claimed[best_target_c] = false;
                        else bot_claimed[best_target_c] = false;

                        bool found_alt = false;
                        // Try building an adjacent cell that's also on this wall
                        for (int dc = -1; dc <= 1; dc += 2) {
                            int nc = best_target_c + dc;
                            if (nc < 1 || nc > GRID_SIZE) continue;
                            if (grid[best_target_r][nc]) continue;
                            if ((best_target_r == top_wall_row && top_claimed[nc]) ||
                                (best_target_r == bot_wall_row && bot_claimed[nc])) continue;
                            if (!can_build_wall(best_target_r, nc)) continue;

                            // Can we build it from current position?
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == best_target_r &&
                                    humans[i].c + DC[d] == nc) {
                                    actions[i] = BUILD_CH[d];
                                    walls_being_built.push_back({best_target_r, nc});
                                    if (best_target_r == top_wall_row) top_claimed[nc] = true;
                                    else bot_claimed[nc] = true;
                                    found_alt = true;
                                    break;
                                }
                            }
                            if (found_alt) break;
                        }

                        if (!found_alt) {
                            // Try the OTHER wall
                            int other_wall = (best_target_r == top_wall_row) ? bot_wall_row : top_wall_row;
                            bool* other_claimed = (best_target_r == top_wall_row) ? bot_claimed : top_claimed;
                            bool other_complete_flag = (best_target_r == top_wall_row) ? bot_complete : top_complete;

                            if (!other_complete_flag && other_wall >= 1 && other_wall <= 30) {
                                int other_stand_r = (other_wall == top_wall_row) ? top_wall_row + 1 : bot_wall_row - 1;
                                // Can we build on the other wall from adjacent position?
                                for (int d = 0; d < 4; d++) {
                                    int wr = humans[i].r + DR[d];
                                    int wc = humans[i].c + DC[d];
                                    if (wr == other_wall && wc >= 1 && wc <= GRID_SIZE &&
                                        !grid[other_wall][wc] && !other_claimed[wc] &&
                                        can_build_wall(wr, wc)) {
                                        actions[i] = BUILD_CH[d];
                                        walls_being_built.push_back({wr, wc});
                                        other_claimed[wc] = true;
                                        found_alt = true;
                                        break;
                                    }
                                }
                            }
                        }

                        if (!found_alt) actions[i] = '.';
                    }
                } else {
                    // Move toward stand position, staying within band
                    if (!passable(stand_pos.r, stand_pos.c)) {
                        actions[i] = '.';
                    } else {
                        actions[i] = move_toward(humans[i], stand_pos);
                    }
                }
            }

            if (human_phase[i] == PHASE_DONE) {
                actions[i] = '.';
            }
        }

        // Validate moves - don't move into walls being built or impassable
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
