            int area_below = (GRID_SIZE - br) * GRID_SIZE;

            // Humans in each zone: roughly M/2 each
            int humans_top = M / 2;
            int humans_bot = M - humans_top;

            double score_above = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
            double score_below = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);

            // Average satisfaction
            double avg_score = (score_above * humans_top + score_below * humans_bot) / M;

            // Penalize if walls are far from humans
            double avg_dist_top = 0, avg_dist_bot = 0;
            for (int i = 0; i < M; i++) {
                avg_dist_top += std::abs(humans[i].r - tr);
                avg_dist_bot += std::abs(humans[i].r - br);
            }
            avg_dist_top /= M;
            avg_dist_bot /= M;
            double avg_dist = (avg_dist_top + avg_dist_bot) / 2.0;

            // Penalize: building two walls of 30 each takes ~60/M turns + travel
            double time_penalty = 1.0 / (1.0 + avg_dist * 0.03);

            double score = avg_score * time_penalty;

            if (score > best_score) {
                best_score = score;
                best_top = tr;
                best_bot = br;
            }
        }
    }

